// Coastal Lighthouse — BREP showcase using new APIs.
//
// Stack (z=0 ground), with 0.5mm overlaps at every junction so fuseAll
// produces one solid (not N touching pieces):
//   base plinth     : cylinder(14, 6)              z: 0..6     label 'base'
//   tower stripes   : 6 cylinder(10, 8.5) stacked  z: 5.5..54.5
//                       bottoms at z=5.5,13.5,21.5,29.5,37.5,45.5
//                       labels alternate 'stripeW' / 'stripeR'
//   balcony floor   : cylinder(11.5, 2.5) at z=53  z: 53..55.5  label 'balcony'
//   railing         : torus(11, 1.2) at z=56       z: 54.8..57.2 label 'railing'
//   rail posts      : circularPattern(cylinder(0.4,4),8,{radius:11}) at z=52.5 z:52.5..56.5 label 'posts'
//   lantern room    : cylinder(8, 8.5) at z=57.5   z: 57.5..66  label 'lantern'
//   conical roof    : cone(8, 0, 6.5) at z=65.5    z: 65.5..72  label 'roof'
//   door cut        : box([3,1.5,5]) on +Y of the base
//
// Total height ~72 mm. All major features labelled for paintByLabels.

const { BREP } = api;

// --- Base plinth (dark basalt) ---------------------------------------------
const base = BREP.label(BREP.cylinder(14, 6), 'base');

// --- Door — thin box cut into +Y of the base. The cutter is labelled so
// the recess walls carry the 'door' label after the boolean.
const doorCutter = BREP.label(
  BREP.box([3, 1.5, 5]).translate([0, 13, 0.5]),
  'door',
);
const baseWithDoor = base.cut(doorCutter);

// --- Tower stripes: 6 cylinders each 8.5mm tall, alternating labels.
// Bottoms at z = 5.5, 13.5, 21.5, 29.5, 37.5, 45.5 — each pair overlaps the
// next by 0.5mm (so consecutive cylinders volumetrically union) and the
// first overlaps the base top (z=6) by 0.5mm.
const stripeLabels = ['stripeW1', 'stripeR1', 'stripeW2', 'stripeR2', 'stripeW3', 'stripeR3'];
const stripes = stripeLabels.map((lbl, i) => {
  const z = 5.5 + i * 8;
  return BREP.label(BREP.cylinder(10, 8.5).translate([0, 0, z]), lbl);
});

// --- Balcony floor — overlap into the shaft bottom and railing above.
const balconyFloor = BREP.label(
  BREP.cylinder(11.5, 2.5).translate([0, 0, 53]),
  'balcony',
);

// --- Railing torus — overlaps balcony floor (z=53..55.5) and posts.
const railing = BREP.label(
  BREP.torus(11, 1.2).translate([0, 0, 56]),
  'railing',
);

// --- Rail posts (8 around). circularPattern at radius=11; each post is
// 0.4mm radius x 4mm tall. Translated to z=52.5 so they overlap both the
// balcony floor (z=53..55.5) and the railing (z=54.8..57.2).
const onePost = BREP.cylinder(0.4, 4);
const postsRing = BREP.circularPattern(onePost, 8, { radius: 11 });
const posts = BREP.label(postsRing.translate([0, 0, 52.5]), 'posts');

// --- Lantern room — overlaps balcony and roof.
const lantern = BREP.label(
  BREP.cylinder(8, 8.5).translate([0, 0, 57.5]),
  'lantern',
);

// --- Conical roof — overlaps the lantern top by 0.5mm so it fuses cleanly.
const roof = BREP.label(
  BREP.cone(8, 0, 6.5).translate([0, 0, 65.5]),
  'roof',
);

// Fuse everything into one solid.
return BREP.fuseAll([
  baseWithDoor,
  ...stripes,
  balconyFloor,
  railing,
  posts,
  lantern,
  roof,
]);

